import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import "../index.css";

function Register({ setSuccessMessage }) {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [otp, setOtp] = useState("");
  const [step, setStep] = useState(1);
  const [errorMessage, setErrorMessage] = useState("");
  const navigate = useNavigate();

  const handleRegister = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch("http://localhost:5000/api/register", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name, email, password }),
      });
      const data = await res.json();
      if (res.ok) {
        setStep(2);
        setErrorMessage("");
        alert(data.message);
      } else {
        setErrorMessage(data.message || "Register failed");
      }
    } catch (err) {
      setErrorMessage("❌ Server error. Try again.");
      console.error("frontend register error:", err);
    }
  };

  const handleVerifyOtp = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch("http://localhost:5000/api/verify-otp", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, otp }),
      });
      const data = await res.json();
      if (res.ok) {
        setSuccessMessage("✅ Registration successful!");
        setErrorMessage("");
        navigate("/login");
      } else {
        setErrorMessage(data.message || "OTP verification failed");
      }
    } catch (err) {
      setErrorMessage("❌ OTP verification failed");
      console.error("frontend verify-otp error:", err);
    }
  };

  return (
    <div className="form-container">
      <h2>Register</h2>
      {step === 1 && (
        <form onSubmit={handleRegister}>
          <input type="text" placeholder="Name" value={name} onChange={(e)=>setName(e.target.value)} required />
          <input type="email" placeholder="Email" value={email} onChange={(e)=>setEmail(e.target.value)} required />
          <input type="password" placeholder="Password" value={password} onChange={(e)=>setPassword(e.target.value)} required />
          <button type="submit">Register</button>
        </form>
      )}
      {step === 2 && (
        <form onSubmit={handleVerifyOtp}>
          <p>We sent an OTP to your email. Enter it below:</p>
          <input type="text" placeholder="Enter OTP" value={otp} onChange={(e)=>setOtp(e.target.value)} required />
          <button type="submit">Verify OTP</button>
        </form>
      )}
      {errorMessage && <p className="error">{errorMessage}</p>}
      <p>Already have an account? <Link to="/login">Login</Link></p>
    </div>
  );
}

export default Register;
